const ticker = String($input.first().json.ticker || '')
  .trim()
  .toUpperCase();

if (!ticker) {
  throw new Error('Ticker is missing');
}

// מילון בסיסי עבור ה-MVP
const companies = {
  AAPL: {
    companyName: 'Apple',
    aliases: ['Apple', 'Apple Inc', 'AAPL']
  },
  TSLA: {
    companyName: 'Tesla',
    aliases: ['Tesla', 'Tesla Inc', 'TSLA']
  },
  NVDA: {
    companyName: 'Nvidia',
    aliases: ['Nvidia', 'NVIDIA Corporation', 'NVDA']
  },
  MSFT: {
    companyName: 'Microsoft',
    aliases: ['Microsoft', 'Microsoft Corporation', 'MSFT']
  },
  AMZN: {
    companyName: 'Amazon',
    aliases: ['Amazon', 'Amazon.com', 'AMZN']
  },
  GOOGL: {
    companyName: 'Alphabet',
    aliases: ['Google', 'Alphabet', 'Alphabet Inc', 'GOOGL']
  },
  META: {
    companyName: 'Meta',
    aliases: ['Meta', 'Meta Platforms', 'Facebook', 'META']
  }
};

const company = companies[ticker] || {
  companyName: ticker,
  aliases: [ticker]
};

return [
  {
    json: {
      ticker,
      companyName: company.companyName,
      aliases: company.aliases
    }
  }
];

const input = $input.first().json;

const ticker = String(input.ticker || '')
  .trim()
  .toUpperCase();

if (!ticker) {
  throw new Error('Ticker is missing');
}

const baseUrl = 'https://www.sec.gov/cgi-bin/browse-edgar';

const filingTypes = [
  {
    filingType: '8-K',
    source: 'SEC EDGAR - 8-K Filings'
  },
  {
    filingType: '10-Q',
    source: 'SEC EDGAR - 10-Q Filings'
  },
  {
    filingType: '10-K',
    source: 'SEC EDGAR - 10-K Filings'
  }
];

return filingTypes.map(feed => {
  const feedUrl =
    `${baseUrl}` +
    `?action=getcompany` +
    `&CIK=${encodeURIComponent(ticker)}` +
    `&type=${encodeURIComponent(feed.filingType)}` +
    `&owner=exclude` +
    `&count=40` +
    `&output=atom`;

  return {
    json: {
      ticker: ticker,
      companyName: input.companyName || ticker,
      aliases: input.aliases || [ticker],
      filingType: feed.filingType,
      source: feed.source,
      feedUrl: feedUrl
    }
  };
});

const items = $input.all();

items.sort((a, b) => {
  const dateA = new Date(a.json.published || 0).getTime();
  const dateB = new Date(b.json.published || 0).getTime();

  return dateB - dateA;
});

return items;

const html = String($json.filing_index_html ?? '');

if (!html) {
  throw new Error('לא התקבל filing_index_html');
}

// הנתונים המקוריים מה-Limit
const original = $('Limit').item.json;

const filingUrl = String(original.link ?? '').trim();
const formType = String(original.filingType ?? '')
  .trim()
  .toUpperCase();

if (!filingUrl) {
  throw new Error('לא נמצא link מהצומת Limit');
}

function stripTags(value) {
  return String(value)
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&#160;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

// בניית כתובת SEC מלאה בלי להשתמש ב-new URL
function buildSecUrl(href) {
  let decodedHref = String(href)
    .replace(/&amp;/gi, '&')
    .trim();

  if (!decodedHref) {
    return '';
  }

  // קישור מלא
  if (
    decodedHref.startsWith('https://') ||
    decodedHref.startsWith('http://')
  ) {
    return decodedHref;
  }

  // קישור iXBRL מהצורה:
  // /ix?doc=/Archives/edgar/data/.../file.htm
  if (decodedHref.startsWith('/ix?doc=')) {
    return (
      'https://www.sec.gov' +
      decodedHref.substring('/ix?doc='.length)
    );
  }

  // קישור יחסי שמתחיל ב-/
  if (decodedHref.startsWith('/')) {
    return 'https://www.sec.gov' + decodedHref;
  }

  // קישור יחסי ללא /
  const lastSlash = filingUrl.lastIndexOf('/');

  if (lastSlash !== -1) {
    return (
      filingUrl.substring(0, lastSlash + 1) +
      decodedHref
    );
  }

  return '';
}

const rows = [
  ...html.matchAll(/<tr[^>]*>([\s\S]*?)<\/tr>/gi)
];

const documents = [];

for (const rowMatch of rows) {
  const rowHtml = rowMatch[1];

  const cells = [
    ...rowHtml.matchAll(
      /<td[^>]*>([\s\S]*?)<\/td>/gi
    )
  ].map(match => stripTags(match[1]));

  const linkMatch = rowHtml.match(
    /<a[^>]*href\s*=\s*["']([^"']+)["'][^>]*>/i
  );

  if (!linkMatch || cells.length < 4) {
    continue;
  }

  const href = linkMatch[1];
  const documentUrl = buildSecUrl(href);

  if (!documentUrl) {
    continue;
  }

  const sequence = cells[0] ?? '';
  const description = cells[1] ?? '';
  const documentName = cells[2] ?? '';
  const documentType = String(
    cells[3] ?? ''
  ).toUpperCase();

  const shouldIgnore =
    /\.(jpg|jpeg|png|gif|xml|xsd|css)$/i.test(
      documentName
    ) ||
    documentType.includes('EX-101') ||
    documentType.includes('GRAPHIC') ||
    description
      .toLowerCase()
      .includes('complete submission text file');

  if (!shouldIgnore) {
    documents.push({
      sequence,
      description,
      document_name: documentName,
      document_type: documentType,
      document_url: documentUrl
    });
  }
}

if (documents.length === 0) {
  throw new Error(
    `לא נמצאו מסמכים שימושיים. נמצאו ${rows.length} שורות HTML`
  );
}

// זיהוי 8-K של תוצאות כספיות
const isEarnings8K =
  formType === '8-K' &&
  String(original.itemsDescription ?? '')
    .toLowerCase()
    .includes('2.02');

let selectedDocument;

if (isEarnings8K) {
  // ב-8-K של תוצאות נעדיף את הודעת התוצאות
  selectedDocument =
    documents.find(
      doc => doc.document_type === 'EX-99.1'
    ) ??
    documents.find(
      doc => doc.document_type.startsWith('EX-99')
    ) ??
    documents.find(
      doc => doc.document_type === '8-K'
    ) ??
    documents[0];
} else {
  // ב-10-Q, 10-K וב-8-K רגיל נעדיף את הדוח הראשי
  selectedDocument =
    documents.find(
      doc => doc.document_type === formType
    ) ??
    documents.find(
      doc => doc.sequence === '1'
    ) ??
    documents[0];
}

return {
  json: {
    ...original,

    document_url:
      selectedDocument.document_url,

    document_type:
      selectedDocument.document_type,

    document_description:
      selectedDocument.description,

    selection_reason:
      isEarnings8K &&
      selectedDocument.document_type.startsWith(
        'EX-99'
      )
        ? 'Earnings 8-K: selected earnings exhibit'
        : 'Selected primary filing document',

    available_documents: documents
  }
};

const rawHtml = String($json.document_html ?? '');

if (!rawHtml) {
  throw new Error(
    'לא התקבל document_html מהצומת Get Main Document'
  );
}

// שמירת המטא-דאטה מהשלב שבו נבחר המסמך
const metadata =
  $('Find Main Document or Exhibit').item.json;

// פענוח HTML entities נפוצים וגם entities מספריים
function decodeHtmlEntities(text) {
  return String(text)
    .replace(/&#(\d+);/g, (_, code) => {
      return String.fromCodePoint(Number(code));
    })
    .replace(/&#x([0-9a-f]+);/gi, (_, code) => {
      return String.fromCodePoint(parseInt(code, 16));
    })
    .replace(/&nbsp;/gi, ' ')
    .replace(/&ensp;/gi, ' ')
    .replace(/&emsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&apos;/gi, "'")
    .replace(/&#39;/gi, "'")
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&ndash;/gi, '–')
    .replace(/&mdash;/gi, '—')
    .replace(/&ldquo;/gi, '“')
    .replace(/&rdquo;/gi, '”')
    .replace(/&lsquo;/gi, '‘')
    .replace(/&rsquo;/gi, '’')
    .replace(/&bull;/gi, '•');
}

let cleaned = rawHtml;

// הסרת החלק הטכני והנסתר של Inline XBRL.
// חלק זה מכיל contexts, schemas ויחידות ולא טקסט קריא מהדוח.
cleaned = cleaned.replace(
  /<ix:header\b[^>]*>[\s\S]*?<\/ix:header>/gi,
  ' '
);

// הסרת קוד ותוכן שאינו חלק מהטקסט העסקי
cleaned = cleaned
  .replace(/<script\b[^>]*>[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style\b[^>]*>[\s\S]*?<\/style>/gi, ' ')
  .replace(/<noscript\b[^>]*>[\s\S]*?<\/noscript>/gi, ' ')
  .replace(/<!--[\s\S]*?-->/g, ' ');

// יצירת הפרדות בין שורות וטבלאות לפני הסרת התגיות
cleaned = cleaned
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/p>/gi, '\n\n')
  .replace(/<\/div>/gi, '\n')
  .replace(/<\/section>/gi, '\n\n')
  .replace(/<\/h[1-6]>/gi, '\n\n')
  .replace(/<\/li>/gi, '\n')
  .replace(/<\/tr>/gi, '\n')
  .replace(/<\/td>/gi, ' | ')
  .replace(/<\/th>/gi, ' | ')
  .replace(/<\/table>/gi, '\n\n')
  .replace(/<hr\b[^>]*>/gi, '\n\n');

// הסרת כל שאר תגיות ה־HTML וה־XBRL.
// הטקסט שבתוך התגיות נשמר.
cleaned = cleaned.replace(/<[^>]+>/g, ' ');

// פענוח תווים מיוחדים
cleaned = decodeHtmlEntities(cleaned);

// ניקוי רווחים ותווי בקרה
cleaned = cleaned
  .replace(
    /[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g,
    ' '
  )
  .replace(/\r\n/g, '\n')
  .replace(/\r/g, '\n')
  .replace(/[ \t]+/g, ' ')
  .replace(/ *\| */g, ' | ')
  .replace(/[ \t]+\n/g, '\n')
  .replace(/\n[ \t]+/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

if (!cleaned) {
  throw new Error(
    'לא נשאר טקסט לאחר ניקוי ה-HTML'
  );
}

return {
  json: {
    ...metadata,

    original_html_characters: rawHtml.length,
    cleaned_text_characters: cleaned.length,

    cleaned_text: cleaned
  }
};

const text = String($json.cleaned_text ?? '').trim();

if (!text) {
  throw new Error('לא התקבל cleaned_text');
}

const filingType = String(
  $json.filingType ?? $json.document_type ?? ''
)
  .trim()
  .toUpperCase();

const documentType = String(
  $json.document_type ?? ''
)
  .trim()
  .toUpperCase();

function normalizeText(value) {
  return String(value)
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/[ \t]+/g, ' ')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n[ \t]+/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

/*
 * מחזירה את כל המיקומים שבהם תבנית מסוימת מופיעה.
 */
function findAllIndices(source, patterns) {
  const indices = [];

  for (const pattern of patterns) {
    const regex = new RegExp(pattern, 'gi');

    let match;

    while ((match = regex.exec(source)) !== null) {
      indices.push(match.index);

      // הגנה מפני Regex שלא מתקדם
      if (match.index === regex.lastIndex) {
        regex.lastIndex++;
      }
    }
  }

  return [...new Set(indices)].sort((a, b) => a - b);
}

/*
 * בוחרת את ההופעה הראשונה שנמצאת אחרי minIndex.
 * שימושי כדי לדלג על תוכן העניינים.
 */
function findFirstAfter(source, patterns, minIndex = 0) {
  const indices = findAllIndices(source, patterns);

  return (
    indices.find(index => index >= minIndex) ??
    -1
  );
}

/*
 * בוחרת את ההופעה האחרונה של אחת מהכותרות.
 * שימושי בכותרות שמופיעות פעם בתוכן העניינים
 * ופעם נוספת בגוף הדוח.
 */
function findLastIndex(source, patterns) {
  const indices = findAllIndices(source, patterns);

  if (indices.length === 0) {
    return -1;
  }

  return indices[indices.length - 1];
}

/*
 * מוצאת את סוף הסעיף לאחר מיקום ההתחלה.
 */
function findEndAfter(
  source,
  endPatterns,
  startIndex,
  fallbackLength
) {
  const possibleEnds = [];

  for (const pattern of endPatterns) {
    const regex = new RegExp(pattern, 'gi');
    regex.lastIndex = startIndex + 20;

    const match = regex.exec(source);

    if (match && match.index > startIndex) {
      possibleEnds.push(match.index);
    }
  }

  if (possibleEnds.length > 0) {
    return Math.min(...possibleEnds);
  }

  return Math.min(
    source.length,
    startIndex + fallbackLength
  );
}

function extractSectionByStart(
  source,
  startIndex,
  endPatterns,
  maxCharacters
) {
  if (startIndex === -1) {
    return '';
  }

  const endIndex = findEndAfter(
    source,
    endPatterns,
    startIndex,
    maxCharacters
  );

  const finalEnd = Math.min(
    endIndex,
    startIndex + maxCharacters
  );

  return source
    .slice(startIndex, finalEnd)
    .trim();
}

function addSection(sections, title, content) {
  if (!content || content.length < 100) {
    return;
  }

  sections.push(
    `===== ${title} =====\n${content}`
  );
}

const normalized = normalizeText(text);
const sections = [];

let selectionStrategy = '';

/*
 * נשתמש בנקודת התחלה מינימלית כדי לדלג על
 * העמוד הראשון ועל תוכן העניינים.
 */
const skipBeginningIndex = Math.floor(
  normalized.length * 0.05
);

/*
 * 8-K של תוצאות כספיות.
 */
if (
  filingType === '8-K' &&
  documentType.startsWith('EX-99')
) {
  selectionStrategy =
    'Earnings release: kept results, outlook and business highlights';

  let earningsText = normalized;

  /*
   * חותכים לפני boilerplate משפטי/תקשורתי.
   * משאירים את התוצאות, התחזית וה־Highlights.
   */
  const boilerplateStart = findFirstAfter(
    earningsText,
    [
      'Conference Call and Webcast Information',
      'Non-GAAP Measures',
      'About NVIDIA',
      'For further information, contact',
      'Certain statements in this press release'
    ],
    3000
  );

  if (boilerplateStart !== -1) {
    earningsText = earningsText.slice(
      0,
      boilerplateStart
    );
  }

  addSection(
    sections,
    'EARNINGS RELEASE',
    earningsText.slice(0, 30000)
  );
}

/*
 * 8-K רגיל.
 */
else if (filingType === '8-K') {
  selectionStrategy =
    'Current report: selected disclosed event';

  const itemStart = findLastIndex(
    normalized,
    [
      'Item\\s+1\\.01\\.',
      'Item\\s+2\\.01\\.',
      'Item\\s+2\\.02\\.',
      'Item\\s+3\\.01\\.',
      'Item\\s+5\\.02\\.',
      'Item\\s+7\\.01\\.',
      'Item\\s+8\\.01\\.'
    ]
  );

  const eventSection = extractSectionByStart(
    normalized,
    itemStart,
    [
      '\\nItem\\s+9\\.01\\.',
      '\\nSIGNATURE\\n'
    ],
    15000
  );

  addSection(
    sections,
    'CURRENT EVENT',
    eventSection || normalized.slice(0, 15000)
  );
}

/*
 * 10-Q ו־10-K.
 */
else if (
  filingType === '10-Q' ||
  filingType === '10-K'
) {
  selectionStrategy =
    'Periodic report: selected actual filing sections after table of contents';

  /*
   * 1. דוחות כספיים
   *
   * בכוונה מחפשים רק אחרי 5% מתחילת המסמך,
   * כדי לא לבחור את הכותרת שבתוכן העניינים.
   */
  const financialStart = findFirstAfter(
    normalized,
    [
      'Condensed Consolidated Statements of Income\\s*\\n',
      'Consolidated Statements of Income\\s*\\n',
      'Consolidated Statements of Operations\\s*\\n'
    ],
    skipBeginningIndex
  );

  const financialStatements =
    extractSectionByStart(
      normalized,
      financialStart,
      [
        '\\nNotes to Condensed Consolidated Financial Statements',
        '\\nNotes to Consolidated Financial Statements'
      ],
      12000
    );

  addSection(
    sections,
    'FINANCIAL STATEMENTS',
    financialStatements
  );

  /*
   * 2. MD&A
   *
   * נבחרת ההופעה האחרונה, כדי לא לבחור
   * את הכותרת מתוכן העניינים.
   */
  const managementStart = findLastIndex(
    normalized,
    filingType === '10-Q'
      ? [
          "Item\\s+2\\.\\s*Management['’]s Discussion and Analysis"
        ]
      : [
          "Item\\s+7\\.\\s*Management['’]s Discussion and Analysis"
        ]
  );

  const managementDiscussion =
    extractSectionByStart(
      normalized,
      managementStart,
      filingType === '10-Q'
        ? [
            '\\nItem\\s+3\\.\\s*Quantitative',
            '\\nItem\\s+4\\.\\s*Controls'
          ]
        : [
            '\\nItem\\s+7A\\.',
            '\\nItem\\s+8\\.'
          ],
      22000
    );

  addSection(
    sections,
    'MANAGEMENT DISCUSSION AND ANALYSIS',
    managementDiscussion
  );

  /*
   * 3. Risk Factors
   *
   * נעדיף כותרת Item 1A האמיתית,
   * ולא אזכור כללי של הביטוי Risk Factors.
   */
  const riskStart = findLastIndex(
    normalized,
    [
      'Item\\s+1A\\.\\s*Risk Factors'
    ]
  );

  const riskFactors = extractSectionByStart(
    normalized,
    riskStart,
    [
      '\\nItem\\s+1B\\.',
      '\\nItem\\s+2\\.',
      '\\nItem\\s+3\\.',
      '\\nItem\\s+5\\.',
      '\\nItem\\s+6\\.'
    ],
    12000
  );

  addSection(
    sections,
    'RISK FACTORS',
    riskFactors
  );

  /*
   * 4. נזילות ומקורות הון
   */
  const liquidityStart = findLastIndex(
    normalized,
    [
      'Liquidity and Capital Resources'
    ]
  );

  const liquidity = extractSectionByStart(
    normalized,
    liquidityStart,
    [
      '\\nCapital Return to Shareholders',
      '\\nOutstanding Indebtedness',
      '\\nMaterial Cash Requirements',
      '\\nItem\\s+3\\.'
    ],
    7000
  );

  addSection(
    sections,
    'LIQUIDITY AND CAPITAL RESOURCES',
    liquidity
  );

  /*
   * 5. Buyback ודיבידנד
   *
   * נעדיף את הסעיף מתוך MD&A:
   * Capital Return to Shareholders
   * ולא את Capital Return Program מתוך ההערות.
   */
  let capitalReturnStart = findLastIndex(
    normalized,
    [
      'Capital Return to Shareholders'
    ]
  );

  if (capitalReturnStart === -1) {
    capitalReturnStart = findLastIndex(
      normalized,
      [
        'Capital Return Program'
      ]
    );
  }

  const capitalReturn = extractSectionByStart(
    normalized,
    capitalReturnStart,
    [
      '\\nOutstanding Indebtedness',
      '\\nMaterial Cash Requirements',
      '\\nItem\\s+2\\.',
      '\\nItem\\s+3\\.',
      '\\nNote\\s+13\\s*-'
    ],
    5000
  );

  addSection(
    sections,
    'CAPITAL RETURN',
    capitalReturn
  );
}

/*
 * fallback לדיווחים אחרים.
 */
else {
  selectionStrategy =
    'Fallback: selected first relevant portion';

  addSection(
    sections,
    'FILING CONTENT',
    normalized.slice(0, 20000)
  );
}

let relevantText = sections.join('\n\n');

if (!relevantText) {
  relevantText = normalized.slice(0, 20000);

  selectionStrategy =
    'Fallback: expected section headings were not found';
}

/*
 * מגבלת אורך סופית.
 */
const MAX_FINAL_CHARACTERS = 50000;

let wasTruncated = false;

if (relevantText.length > MAX_FINAL_CHARACTERS) {
  relevantText =
    relevantText.slice(0, MAX_FINAL_CHARACTERS) +
    '\n\n[Content truncated to fit analysis limit]';

  wasTruncated = true;
}

/*
 * לא מעבירים הלאה שוב את cleaned_text המלא,
 * כדי להקטין את ה־JSON של ה־Workflow.
 */
const {
  cleaned_text,
  available_documents,
  ...metadata
} = $json;

return {
  json: {
    ...metadata,

    selection_strategy: selectionStrategy,

    cleaned_text_characters:
      normalized.length,

    relevant_text_characters:
      relevantText.length,

    relevant_text_truncated:
      wasTruncated,

    selected_sections:
      sections.map(section => {
        const firstLine =
          section.split('\n')[0];

        return firstLine
          .replace(/=/g, '')
          .trim();
      }),

    relevant_text: relevantText
  }
};

const relevantText = String(
  $json.relevant_text ?? ''
).trim();

if (!relevantText) {
  throw new Error(
    'לא התקבל relevant_text מהצומת Select Relevant Filing Content'
  );
}

const ticker = String(
  $json.ticker ?? ''
).trim().toUpperCase();

const companyName = String(
  $json.companyName ?? ''
).trim();

const filingType = String(
  $json.filingType ??
  $json.document_type ??
  ''
).trim().toUpperCase();

const documentType = String(
  $json.document_type ?? ''
).trim().toUpperCase();

const published = String(
  $json.published ?? ''
).trim();

const accessionNumber = String(
  $json.accessionNumber ?? ''
).trim();

const source = String(
  $json.source ?? 'SEC EDGAR'
).trim();

const filingUrl = String(
  $json.link ?? ''
).trim();

const documentUrl = String(
  $json.document_url ?? ''
).trim();

const itemsDescription = String(
  $json.itemsDescription ?? ''
).trim();

const selectedSections = Array.isArray(
  $json.selected_sections
)
  ? $json.selected_sections
  : [];

/*
 * סיווג כללי של המסמך.
 */
let filingCategory = 'other_filing';

if (
  filingType === '8-K' &&
  documentType.startsWith('EX-99')
) {
  filingCategory = 'earnings_release';
} else if (
  filingType === '10-Q' ||
  filingType === '10-K'
) {
  filingCategory = 'periodic_financial_report';
} else if (filingType === '8-K') {
  filingCategory = 'current_event';
}

/*
 * יצירת תאריך קריא.
 */
let filingDate = published;

if (published) {
  const parsedDate = new Date(published);

  if (!Number.isNaN(parsedDate.getTime())) {
    filingDate = parsedDate
      .toISOString()
      .slice(0, 10);
  }
}

/*
 * הוראות שונות לפי סוג הדיווח.
 */
let analysisFocus = '';

if (filingCategory === 'earnings_release') {
  analysisFocus = `
Focus especially on:
- Revenue growth or decline
- Earnings and EPS
- Gross margin
- Guidance and outlook
- Performance by business segment
- Data Center or other major growth areas
- Share repurchases and dividends
- Positive or negative surprises
`;
} else if (
  filingCategory === 'periodic_financial_report'
) {
  analysisFocus = `
Focus especially on:
- Revenue and profitability trends
- Management discussion
- Growth drivers
- Risks and uncertainties
- Liquidity and capital resources
- Customer concentration
- Competition
- Export restrictions and regulation
- Share repurchases and dividends
`;
} else if (filingCategory === 'current_event') {
  analysisFocus = `
Focus especially on:
- What event occurred
- Who is involved
- Effective dates
- Financial or strategic implications
- Whether the event is routine or material
- Possible positive, neutral, or negative impact
`;
}

/*
 * קלט אחיד לסוכן.
 */
const analysisInput = `
You are analyzing an official SEC filing for a financial sentiment workflow.

DOCUMENT METADATA
Company: ${companyName || 'Unknown'}
Ticker: ${ticker || 'Unknown'}
Filing type: ${filingType || 'Unknown'}
Document type: ${documentType || 'Unknown'}
Filing category: ${filingCategory}
Filing date: ${filingDate || 'Unknown'}
SEC items: ${itemsDescription || 'Not specified'}
Accession number: ${accessionNumber || 'Unknown'}
Source: ${source}
Selected sections: ${
  selectedSections.length
    ? selectedSections.join(', ')
    : 'Not specified'
}

ANALYSIS GUIDANCE
Analyze only the information contained in the filing.
Do not invent facts.
Separate factual information from interpretation.
Consider both positive and negative information.
Evaluate the likely financial significance of the filing.
${analysisFocus}

SEC FILING CONTENT
--------------------
${relevantText}
--------------------
END OF SEC FILING CONTENT
`.trim();

/*
 * מסירים שדות גדולים שאין צורך להעביר שוב.
 */
const {
  relevant_text,
  cleaned_text,
  filing_index_html,
  document_html,
  available_documents,
  ...metadata
} = $json;

return {
  json: {
    ...metadata,

    filing_category: filingCategory,
    filing_date: filingDate,

    analysis_metadata: {
      company_name: companyName,
      ticker,
      filing_type: filingType,
      document_type: documentType,
      filing_category: filingCategory,
      filing_date: filingDate,
      accession_number: accessionNumber,
      selected_sections: selectedSections,
      filing_url: filingUrl,
      document_url: documentUrl
    },

    analysis_input_characters:
      analysisInput.length,

    analysis_input: analysisInput
  }
};

const items = $input.all();

if (items.length === 0) {
  throw new Error('לא התקבלו מסמכי SEC');
}

const ticker = String(
  items[0].json.ticker ?? ''
)
  .trim()
  .toUpperCase();

const companyName = String(
  items[0].json.companyName ?? ''
).trim();

const documents = items
  .map((item, index) => {
    const data = item.json;

    const content = String(
      data.analysis_input ?? ''
    ).trim();

    if (!content) {
      return null;
    }

    return `
===== DOCUMENT ${index + 1} =====
${content}
===== END DOCUMENT ${index + 1} =====
`.trim();
  })
  .filter(Boolean);

if (documents.length === 0) {
  throw new Error(
    'לא נמצא analysis_input במסמכים'
  );
}

const documentsText = documents.join('\n\n');

return [
  {
    json: {
      ticker,
      company_name: companyName,
      document_count: documents.length,
      documents_text: documentsText,
      documents_text_characters:
        documentsText.length
    }
  }
];

const items = $input.all();

if (items.length === 0) {
  throw new Error(
    'Financial Sentiment Analyst returned no result'
  );
}

const rawResult = items[0].json;

// לעיתים התוצאה מה-AI Agent נמצאת בתוך output
const initialAnalysis =
  rawResult.output ??
  rawResult;

const analystPayload =
  $('Build Analyst Payload')
    .first()
    .json;

const ticker = String(
  initialAnalysis.ticker ??
  analystPayload.ticker ??
  ''
)
  .trim()
  .toUpperCase();

if (!ticker) {
  throw new Error(
    'Ticker is missing from analyst result'
  );
}

return [
  {
    json: {
      ticker,
      company_name:
        analystPayload.company_name ?? ticker,

      sec_document_count:
        analystPayload.document_count ?? 0,

      initial_analysis:
        initialAnalysis
    }
  }
];
